   165	    fn track_proto_write(assign_expr: &AssignmentExpression<'a>, ctx: &mut TraverseCtx<'a>) {
   166	        // Skip when property_write_side_effects is true (default) — the optimization
   167	        // that drops member writes is disabled, so tracking is unnecessary.
   168	        if ctx.state.options.treeshake.property_write_side_effects {
