   680	        let object = match &assign_expr.left {
   681	            AssignmentTarget::StaticMemberExpression(e) if e.property.name == "__proto__" => {
   682	                &e.object
   683	            }
   684	            // Computed key like `a[b]` could be `"__proto__"`
   685	            AssignmentTarget::ComputedMemberExpression(e) => &e.object,
   686	            _ => return,
