            && let Some(Statement::ExpressionStatement(prev_expr_stmt)) = result.last_mut()
        {
            let a = &mut prev_expr_stmt.expression;
            let b = &mut expr_stmt.expression;
            expr_stmt.expression = Self::join_sequence(a, b, ctx);
